import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        A = [int(next(it)) for _ in range(N)]
        B = [int(next(it)) for _ in range(N)]
        ans = 0
        for a, b in zip(A, B):
            if a == b:
                ans += a
        out_lines.append(str(ans))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

